<div class="d-flex flex-wrap justify-content-between align-items-center gap-2 mb-3"><h1 class="h3 mb-0">Users</h1><div class="d-flex flex-wrap gap-2"><a class="btn btn-outline-primary" href="/portal/users/microsoft"><i class="fa-brands fa-microsoft"></i> Import from Microsoft 365</a><a class="btn btn-outline-secondary" href="/portal/users/microsoft/access"><i class="fa-solid fa-user-shield"></i> Entra access mapping</a><button class="btn btn-primary" data-bs-toggle="collapse" data-bs-target="#newUser"><i class="fa-solid fa-user-plus"></i> New local user</button></div></div>
<div class="collapse mb-4" id="newUser"><div class="card card-body"><form method="post" action="/portal/users" class="row g-3"><?=csrf_field()?><div class="col-md-3"><input class="form-control" name="name" placeholder="Name" required></div><div class="col-md-3"><input class="form-control" type="email" name="email" placeholder="Email" required></div><div class="col-md-2"><input class="form-control" type="password" name="password" placeholder="Temporary password" required></div><div class="col-md-2"><select class="form-select" name="role"><?php foreach(['administrator','owner','office','estimator','crew_leader','technician'] as $r):?><option><?=e($r)?></option><?php endforeach;?></select></div><div class="col-md-2"><button class="btn btn-success w-100">Create</button></div></form></div></div>
<div class="card"><div class="table-responsive"><table class="table table-hover align-middle mb-0"><thead><tr><th>User</th><th>Role / Status</th><th>Manager</th><th>Vehicle</th><th>Territory</th><th></th></tr></thead><tbody><?php foreach($users as $u):?><tr><form method="post" action="/portal/users/<?=e($u['id'])?>"><?=csrf_field()?><td><input class="form-control form-control-sm mb-1" name="name" value="<?=e($u['name'])?>"><input class="form-control form-control-sm" name="email" value="<?=e($u['email'])?>"><div class="small text-muted mt-1"><?=e($u['department'] ?: '')?><?=!empty($u['job_title'])?' · '.e($u['job_title']):''?> <?php if($u['microsoft_object_id']):?><span class="badge text-bg-light border">Entra</span><?php endif?></div></td><td><select class="form-select form-select-sm mb-1" name="role"><?php foreach(['administrator','owner','office','estimator','crew_leader','technician'] as $r):?><option <?=selected($u['role'],$r)?>><?=e($r)?></option><?php endforeach;?></select><select class="form-select form-select-sm" name="status"><option <?=selected($u['status'],'active')?>>active</option><option <?=selected($u['status'],'disabled')?>>disabled</option></select></td><td><?=e($u['entra_manager_name'] ?: '—')?><div class="small text-muted"><?=e($u['entra_manager_email'] ?: '')?></div></td><td><select class="form-select form-select-sm" name="assigned_vehicle_id"><option value="">Unassigned</option><?php foreach($vehicles as $v):?><option value="<?=e($v['id'])?>" <?=selected($u['assigned_vehicle_id'],$v['id'])?>><?=e($v['unit_number'].' '.trim(($v['make']??'').' '.($v['model']??'')))?></option><?php endforeach?></select></td><td><select class="form-select form-select-sm" name="service_territory_id"><option value="">Unassigned</option><?php foreach($territories as $t):?><option value="<?=e($t['id'])?>" <?=selected($u['service_territory_id'],$t['id'])?>><?=e($t['name'])?></option><?php endforeach?></select></td><td><button class="btn btn-sm btn-primary">Save</button></td></form></tr><?php endforeach;?></tbody></table></div></div>
